UPDATE public.settings SET value = '[{"id":"resp_ft","text":"Anh/chị có thường xuyên mua sắm quần áo trực tuyến không?","textEN":"Do you frequently shop for clothes online?","type":"radio","options":["Có","Không"],"optionsEN":["Yes","No"],"required":true,"section":"Thông tin chung","order":1},{"id":"resp_eval","text":"Anh/chị đã từng sử dụng công cụ hoặc hệ thống gợi ý cá nhân hóa thời trang bằng AI nào chưa?","textEN":"Have you ever used an AI-powered personalized fashion recommendation tool?","type":"radio","options":["Có","Không"],"optionsEN":["Yes","No"],"required":true,"section":"Thông tin chung","order":2},{"id":"resp_ai_dev","text":"Anh/chị có quan tâm đến thời trang bền vững, quần áo tái chế (upcycling) không?","textEN":"Are you interested in sustainable fashion or upcycled clothing?","type":"radio","options":["Có","Không"],"optionsEN":["Yes","No"],"required":true,"section":"Thông tin chung","order":3},{"id":"resp_gender","text":"Giới tính","textEN":"Gender","type":"radio","options":["Nam","Nữ","Khác","Không muốn trả lời"],"optionsEN":["Male","Female","Other","Prefer not to say"],"required":true,"section":"Thông tin chung","order":4},{"id":"resp_age","text":"Độ tuổi","textEN":"Age","type":"radio","options":["18-24","25-34","35-44","45-54","Từ 55 trở lên"],"optionsEN":["18-24","25-34","35-44","45-54","55 and above"],"required":true,"section":"Thông tin chung","order":5},{"id":"resp_region","text":"Khu vực sinh sống","textEN":"Living region","type":"radio","options":["TP.HCM","Hà Nội","Miền Bắc khác","Miền Trung - Tây Nguyên","Miền Nam khác"],"optionsEN":["HCMC","Hanoi","Other North","Central - Highlands","Other South"],"required":true,"section":"Thông tin chung","order":6},{"id":"resp_dept","text":"Phong cách thời trang yêu thích của Anh/chị là gì?","textEN":"What is your preferred fashion style?","type":"radio","options":["Thường ngày (Casual)","Công sở (Formal)","Cổ điển (Vintage)","Thể thao (Sporty)","Đường phố (Streetwear)","Khác"],"optionsEN":["Casual","Formal","Vintage","Sporty","Streetwear","Other"],"required":true,"section":"Thông tin chung","order":7},{"id":"resp_experience","text":"Tần suất mua sắm quần áo của Anh/chị?","textEN":"How often do you shop for clothes?","type":"radio","options":["Hàng tuần","Hàng tháng","Vài tháng một lần","Chỉ khi cần thiết","Khác"],"optionsEN":["Weekly","Monthly","Every few months","Only when needed","Other"],"required":true,"section":"Thông tin chung","order":8},{"id":"FC1","text":"Tôi lo ngại bị mất hình ảnh trước người khác nếu sản phẩm do AI gợi ý không phù hợp với tôi.","textEN":"I would be concerned about losing my fashion image if the clothes recommended by the AI did not suit me.","type":"likert","section":"Câu hỏi ban đầu","order":9},{"id":"FC2","text":"Tôi quan tâm đến việc bảo vệ phong cách thời trang cá nhân của mình khi sử dụng gợi ý từ hệ thống AI.","textEN":"I care about protecting my personal style when receiving recommendations from the AI system.","type":"likert","section":"Câu hỏi ban đầu","order":10},{"id":"FC3","text":"Tôi lo ngại người khác sẽ đánh giá tiêu cực hoặc cho rằng tôi có gu thời trang kém nếu mặc đồ tái chế (upcycling) từ ReFashion.","textEN":"I worry that others would judge me negatively or think I have poor style if I wore upcycled clothes from ReFashion.","type":"likert","section":"Câu hỏi ban đầu","order":11},{"id":"FC4","text":"Việc duy trì hình ảnh cá nhân chỉn chu và phong cách là quan trọng đối với tôi khi chọn trang phục.","textEN":"Maintaining a neat and stylish personal image is important to me when selecting outfits.","type":"likert","section":"Câu hỏi ban đầu","order":12},{"id":"MC_TBD1","text":"Giao diện gợi ý của ReFashion dường như được thiết kế để cung cấp thông tin minh bạch ngay từ đầu.","textEN":"The ReFashion recommendation interface appears to be designed with transparency from the outset.","type":"likert","section":"MC: Minh bạch","order":13},{"id":"MC_TBD2","text":"Thông tin giải thích hoặc Hộ chiếu sản phẩm số DPP dường như là một phần không thể thiếu của hệ thống gợi ý thời trang này.","textEN":"The styling explanation or DPP Passport seems to be integrated as an essential part of this recommendation system.","type":"likert","section":"MC: Minh bạch","order":14},{"id":"MC_TBD3","text":"Hệ thống cung cấp thông tin rõ ràng về các sản phẩm và dữ liệu nguồn gốc.","textEN":"The system provides clear information about the products and their sustainability provenance.","type":"likert","section":"MC: Minh bạch","order":15},{"id":"MC_TBD4","text":"Hệ thống giải thích rõ lý do hoặc tiêu chí vì sao sản phẩm này phù hợp với tôi.","textEN":"The system clearly explains the reasons or criteria why this product suits me.","type":"likert","section":"MC: Minh bạch","order":16},{"id":"MC_TBD5","text":"Hệ thống cung cấp lời giải thích dễ hiểu (XAI) cho các gợi ý thời trang.","textEN":"The system provides understandable explanations (XAI) for fashion recommendations.","type":"likert","section":"MC: Minh bạch","order":17},{"id":"MC_TBD6","text":"Hệ thống truyền đạt rõ ràng nguồn gốc và vòng đời sản phẩm thông qua Hộ chiếu sản phẩm số DPP.","textEN":"The system clearly communicates product origin and lifecycle via the Digital Product Passport (DPP).","type":"likert","section":"MC: Minh bạch","order":18},{"id":"MC_TBD7","text":"Hệ thống giúp tôi dễ dàng xác thực tính chính xác của dữ liệu thời trang bền vững.","textEN":"The system helps me easily verify the reliability of sustainable fashion claims.","type":"likert","section":"MC: Minh bạch","order":19},{"id":"MC_OF1","text":"Các sản phẩm gợi ý mà tôi nhận được từ hệ thống AI là rất phù hợp và đẹp mắt.","textEN":"The personalized recommendations I received from the AI system are favorable and appealing.","type":"likert","section":"MC: Kết quả","order":20},{"id":"MC_OF2","text":"Các sản phẩm thời trang tái chế được đề xuất này rất có ích cho nhu cầu của tôi.","textEN":"These recommended upcycled fashion items are beneficial for my needs.","type":"likert","section":"MC: Kết quả","order":21},{"id":"MC_OF3","text":"Các gợi ý thời trang từ hệ thống AI này đúng với những gì tôi mong muốn.","textEN":"The fashion suggestions from the AI system match what I desired.","type":"likert","section":"MC: Kết quả","order":22},{"id":"XAI1","text":"Tôi thấy phần giải thích của ReFashion dễ hiểu.","textEN":"I found the explanation of ReFashion to be easily understandable.","type":"likert","section":"XAI","order":23},{"id":"XAI2","text":"Tôi nghĩ kết quả của ReFashion có thể giải thích được.","textEN":"I think the results of ReFashion are interpretable.","type":"likert","section":"XAI","order":24},{"id":"AIP1","text":"Tính năng cá nhân hóa bằng AI của hệ thống gợi ý ReFashion cung cấp các đề xuất mua sắm phù hợp với nhu cầu của tôi.","textEN":"The AI-powered personalization feature of the ReFashion recommendation system provides purchase suggestions tailored to my needs.","type":"likert","section":"AI Personalization (AIP)","order":25},{"id":"AIP2","text":"Tính năng cá nhân hóa bằng AI của hệ thống gợi ý ReFashion cho phép tôi chọn các sản phẩm được thiết kế riêng cho mình.","textEN":"The AI-powered personalization feature of the ReFashion recommendation system allows me to order products designed specifically for me.","type":"likert","section":"AI Personalization (AIP)","order":26},{"id":"AIP3","text":"Tính năng cá nhân hóa bằng AI của hệ thống gợi ý ReFashion được tùy chỉnh theo nhu cầu của tôi.","textEN":"The AI-powered personalization feature of the ReFashion recommendation system is customized to my needs.","type":"likert","section":"AI Personalization (AIP)","order":27},{"id":"AIP4","text":"Tính năng cá nhân hóa bằng AI của hệ thống gợi ý ReFashion thích nghi với hoàn cảnh của tôi.","textEN":"The AI-powered personalization feature of the ReFashion recommendation system is adapted to my circumstances.","type":"likert","section":"AI Personalization (AIP)","order":28},{"id":"PT1","text":"Ngoài thông tin cơ bản về sản phẩm (thành phần, nơi sản xuất, hạn sử dụng, ..), việc truy xuất nguồn gốc sản phẩm còn giúp nhận diện hàng giả.","textEN":"In addition to the basic information about the product (composition, place of manufacture, expiry date, ..), product traceability also helps identify counterfeit goods.","type":"likert","section":"Product Traceability","order":29},{"id":"PT2","text":"Thông tin về quy trình phân phối quần áo, bao gồm từng giai đoạn vận chuyển và cách xử lý sản phẩm.","textEN":"Information about the clothing distribution process, including each stage of transportation and how the goods are handled.","type":"likert","section":"Product Traceability","order":30},{"id":"CT1","text":"Hệ thống gợi ý thời trang tuần hoàn ReFashion là đáng tin cậy.","textEN":"The ReFashion circular fashion recommendation system is trustworthy.","type":"likert","section":"Consumer Trust","order":31},{"id":"CT2","text":"Tôi có thể tin tưởng vào những gợi ý thời trang từ hệ thống ReFashion.","textEN":"I can trust the fashion recommendations from the ReFashion system.","type":"likert","section":"Consumer Trust","order":32},{"id":"PI1","text":"Tôi có ý định mua quần áo được gợi ý qua hệ thống AI trên nền tảng ReFashion.","textEN":"I intend to buy clothing suggested through the AI system on the ReFashion platform.","type":"likert","section":"Purchase Intention","order":33},{"id":"PI2","text":"Tôi sẵn lòng trả giá cao hơn cho các sản phẩm thời trang bền vững được gợi ý trên ReFashion so với các sản phẩm thông thường.","textEN":"I am willing to pay a higher price for sustainable fashion products suggested on ReFashion than for conventional products.","type":"likert","section":"Purchase Intention","order":34},{"id":"EC1","text":"Tôi rất quan tâm đến các vấn đề bảo vệ môi trường và thời trang bền vững.","textEN":"I am highly concerned about environmental protection and sustainable fashion.","type":"likert","section":"Environment concern","order":35},{"id":"CTRL_AI_FAM","text":"Mức độ am hiểu của Anh/chị về các hệ thống trí tuệ nhân tạo (AI)?","textEN":"How familiar are you with artificial intelligence (AI) systems?","type":"select","options":["Rất thấp","Thấp","Trung bình","Cao","Rất cao"],"optionsEN":["Very low","Low","Medium","High","Very high"],"required":true,"section":"Biến kiểm soát","order":36},{"id":"CTRL_AI_EXP","text":"Anh/chị đã từng sử dụng công cụ AI trong công việc hàng ngày chưa?","textEN":"Have you used AI tools in your daily work?","type":"select","options":["Chưa từng","Thỉnh thoảng","Thường xuyên"],"optionsEN":["Never","Occasionally","Regularly"],"required":true,"section":"Biến kiểm soát","order":37},{"id":"ATT1","text":"Trong gợi ý sản phẩm thời trang trên, tỷ lệ độ phù hợp (Match percentage) là bao nhiêu?","textEN":"In the above recommendation, what is the match percentage?","type":"text","required":true,"section":"Biến kiểm soát","order":38},{"id":"DETAIL_LEVEL","text":"Theo Anh/chị, gợi ý thời trang trên cung cấp mức độ thông tin chi tiết như thế nào?","textEN":"In your opinion, how detailed is the fashion recommendation information provided above?","type":"likert","scaleStart":1,"scaleEnd":7,"labelStart":"Rất sơ sài","labelEnd":"Rất chi tiết","labelStartEN":"Very sketchy","labelEndEN":"Very detailed","required":true,"section":"Biến kiểm soát","order":39},{"id":"email","text":"Nếu Anh/chị có nhu cầu nhận kết quả của nghiên cứu này, chúng tôi sẵn sàng cung cấp sau khi hoàn thành, vui lòng nhập địa chỉ email của Anh/chị hoặc gõ \"Không\" nếu Anh/chị không có nhu cầu.","textEN":"If you wish to receive the results of this study, please enter your email address or type \"No\" if you do not want it.","type":"text","required":true,"section":"Biến kiểm soát","order":40}]'::jsonb WHERE key = 'hr_questions';
